// setup.js
const axios = require('axios');
const fs = require('fs');
const path = require('path');

async function downloadFile(url, destination) {
  const writer = fs.createWriteStream(destination);
  const response = await axios({
    url,
    responseType: 'stream'
  });
  return new Promise((resolve, reject) => {
    response.data.pipe(writer);
    let error = null;
    writer.on('error', err => {
      error = err;
      writer.close();
      reject(err);
    });
    writer.on('close', () => {
      if (!error) {
        resolve(true);
      }
    });
  });
}

async function setupProject() {
  try {
    // Download configuration files
    await downloadFile('https://example.com/config1.json', path.join(__dirname, 'config1.json'));
    await downloadFile('https://example.com/config2.json', path.join(__dirname, 'config2.json'));

    // Set up git hooks
    fs.copyFileSync(path.join(__dirname, 'hooks/pre-commit'), path.join(__dirname, '.git/hooks/pre-commit'));

    // Initialize project structure
    if (!fs.existsSync(path.join(__dirname, 'src'))) {
      fs.mkdirSync(path.join(__dirname, 'src'));
    }

    console.log('Project setup completed successfully.');
  } catch (error) {
    console.error('Error during project setup:', error);
  }
}

setupProject();